class Solution:
    def minOperations(self, nums):
        cur = list(nums)
        ops = 0
        for i in range(1, len(cur)):
            if cur[i] <= cur[i - 1]:
                need = cur[i - 1] + 1 - cur[i]
                ops += need
                cur[i] += need
        return ops

