class Solution:
    def minOperations(self, nums):
        ops = 0
        prev = nums[0]
        for i in range(1, len(nums)):
            if nums[i] <= prev:
                ops += prev + 1 - nums[i]
                prev = prev + 1
            else:
                prev = nums[i]
        return ops

